CREATE TRIGGER LG_ORFLINE_DEL_002_01 ON LG_002_01_ORFLINE
FOR DELETE
AS
DECLARE @LINETYPE       SMALLINT
DECLARE @STOCKREF       INT
DECLARE @VARIANTREF     INT
DECLARE @AMOUNT         FLOAT
DECLARE @SHIPPEDAMOUNT  FLOAT
DECLARE @UINFO1         FLOAT
DECLARE @UINFO2         FLOAT
DECLARE @DT             DATETIME
DECLARE @DORESERVE      SMALLINT
DECLARE @RESERVEDT      DATETIME
DECLARE @CLOSED         SMALLINT
DECLARE @STATUS         SMALLINT
DECLARE @TRCODE         SMALLINT
DECLARE @SOURCEINDEX    SMALLINT
DECLARE @OFFTRREF       INT
DECLARE @OFFREF         INT
DECLARE @PREVLNREF      INT
DECLARE @DETLN          SMALLINT
DECLARE @PREVLNNO       SMALLINT
DECLARE @COEF           SMALLINT
DECLARE @CLREF              INT
DECLARE @REMAMOUNT          FLOAT
DECLARE @old_Trcode         SMALLINT
DECLARE @old_LINENET        FLOAT
DECLARE @old_REPORTRATE     FLOAT
DECLARE @old_BILLED         SMALLINT
DECLARE @_Closed     SMALLINT
DECLARE @VATSTATE     SMALLINT
DECLARE @STRANS      SMALLINT
DECLARE @PROMOTION   SMALLINT
DECLARE @COMPOSITE   SMALLINT
DECLARE @SERVICE     SMALLINT
DECLARE @LCLASS      SMALLINT
DECLARE @VALID       SMALLINT
DECLARE @CANCELL     SMALLINT
DECLARE @AFFECTCOLLTRL SMALLINT
DECLARE @AFFECTRISK SMALLINT
DECLARE @WITHPAYTRANS SMALLINT
SELECT  @STRANS    = 0,
        @PROMOTION = 1,
        @SERVICE   = 4,
        @COMPOSITE = 6,
        @LCLASS    = 10
SELECT @LINETYPE      = D.LINETYPE,
       @STOCKREF      = D.STOCKREF,
       @VARIANTREF    = D.VARIANTREF,
       @AMOUNT        = D.AMOUNT,
       @SHIPPEDAMOUNT = D.SHIPPEDAMOUNT,
       @UINFO1        = D.UINFO1,
       @UINFO2        = D.UINFO2,
       @DT            = D.DATE_,
       @DORESERVE     = D.DORESERVE,
       @RESERVEDT     = D.RESERVEDATE,
       @CLOSED        = D.CLOSED,
       @CANCELL       = D.CANCELLED,
       @STATUS        = D.STATUS,
       @TRCODE        = D.TRCODE,
       @VATSTATE      = D.VATINC,
       @SOURCEINDEX   = D.SOURCEINDEX,
       @OFFTRREF      = D.OFFTRANSREF,
       @OFFREF        = D.OFFERREF,
       @PREVLNREF     = D.PREVLINEREF,
       @DETLN         = D.DETLINE,
       @PREVLNNO      = D.PREVLINENO,
       @AFFECTCOLLTRL = D.AFFECTCOLLATRL,
       @AFFECTRISK    = D.AFFECTRISK,
       @WITHPAYTRANS    = D.WITHPAYTRANS       FROM DELETED D
IF @CANCELL=1
 BEGIN
  SELECT @CLOSED = 1
 END
EXECUTE LG_UPDATE_ORDTRANS_002_01 @LINETYPE, @STOCKREF, @VARIANTREF, @AMOUNT, @SHIPPEDAMOUNT, @UINFO1, @UINFO2,
                                  @DT, @DORESERVE, @RESERVEDT, @CLOSED, @STATUS, @TRCODE, @SOURCEINDEX,
                                  @OFFTRREF, @OFFREF, @PREVLNREF, @DETLN, @PREVLNNO, -1, 0
SELECT @VALID = 0
IF    ((@LINETYPE = @STRANS)  OR
       (@LINETYPE = @COMPOSITE) OR (@LINETYPE = @SERVICE) OR (@LINETYPE = @LCLASS))
 SELECT @VALID = 1
SELECT  @REMAMOUNT = D.AMOUNT - D.SHIPPEDAMOUNT - D.SHIPPEDAMNTSUGG, @_Closed=D.CLOSED FROM DELETED D
IF @REMAMOUNT<0
 set @REMAMOUNT=0
IF @_Closed=0
BEGIN
SELECT @CLREF = D.CLIENTREF,
       @old_TrCode = D.TRCODE,
       @old_ReportRate = D.REPORTRATE,
       @old_BILLED = D.BILLEDITEM FROM DELETED D
if @VALID=1
BEGIN
 SELECT @old_LINENET=(D.LINENET - D.DISTDISC + D.DISTEXP + D.DISTCOST + D.VATAMNT + D.DISTEXPVAT + D.ADDTAXAMOUNT + D.DISTDISCVAT) FROM DELETED D
 select @old_LINENET=(@old_LINENET/D.AMOUNT)*@REMAMOUNT FROM DELETED D
END
IF (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (ISNULL(@AFFECTRISK,0)= 0 ) AND (ISNULL(@WITHPAYTRANS,0)=0)  AND (@VALID=1)
 EXECUTE LG_UPDATECLCARDRISKNUMS_002_01 @CLREF, @old_TRCODE, @old_LINENET, 1, @old_ReportRate, @old_BILLED, @Status, 0, 0
IF (@LINETYPE <> @PROMOTION) AND (@DETLN = 0) AND (@AFFECTCOLLTRL=1)  AND (@VALID=1)
 EXECUTE LG_UPDCOLLATRLRISK_002_01 @CLREF, @old_TRCODE, @old_LINENET, 1, @old_ReportRate, @old_BILLED, @Status, 0, 0
END
IF @STOCKREF <> 0
 EXECUTE LG_UPDATEMRPITMCHNG_002 @STOCKREF, @VARIANTREF, @PREVLNREF
